  1→import {
  2→  NavigationProp,
  3→  useFocusEffect,
  4→  useNavigation,
  5→} from '@react-navigation/native';
  6→import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
  7→import React, { FC, useEffect, useMemo, useRef, useState } from 'react';
  8→import { Dimensions } from 'react-native';
  9→
 10→import { useScreenViewTracking } from '../../hooks/tracking';
 11→import { usePoints } from '../../services';
 12→
 13→import {
 14→  eventModalView,
 15→  eventScreenViewV3,
 16→  eventSelectContent,
 17→} from '~/constants/functions';
 18→import { PropsRootStack } from '../../routes/Models';
 19→import {
 20→  formatCurrencyBR,
 21→  getFormattedPoints,
 22→  getParsedCurrency,
 23→  getParsePoints,
 24→} from '../../utils/functions';
 25→import { CashbackInvoiceItem, InvoiceCashbackProps } from './models';
 26→import InvoiceCashbackPointsView from './view';
 27→
 28→const InvoiceCashbackPoints: FC<InvoiceCashbackProps> = ({ route }) => {
 29→  const {
 30→    points,
 31→    pointsQuantity,
 32→    isLoadingParameterization,
 33→    requestParameterization,
 34→  } = usePoints();
 35→  useScreenViewTracking({
 36→    route,
 37→    title: 'Cashback na fatura',
 38→  });
 39→  const { height, width } = Dimensions.get('window');
 40→
 41→  useEffect(() => {
 42→    requestParameterization();
 43→  }, [requestParameterization]);
 44→
 45→  const hasFocused = useRef(false);
 46→  useFocusEffect(
 47→    React.useCallback(() => {
 48→      if (!hasFocused.current) {
 49→        eventScreenViewV3(
 50→          'desconto_fatura',
 51→          'hub_recompensas_spmais',
 52→          'monetizacao',
 53→          {
 54→            location_1: 'monetizacao',
 55→            location_2: 'hub_recompensas_spmais',
 56→            location_3: 'desconto_fatura',
 57→          },
 58→        );
 59→        hasFocused.current = true;
 60→      }
 61→      return () => {
 62→        hasFocused.current = false;
 63→      };
 64→    }, []),
 65→  );
 66→
 67→  const navigation = useNavigation<NavigationProp<PropsRootStack>>();
 68→
 69→  const conversionFactor = route?.params?.conversionFactor ?? 0;
 70→  const pointsPrice = Number(
 71→    (Math.trunc(points || 0) * conversionFactor).toFixed(2),
 72→  );
 73→
 74→  const finalPrice = pointsPrice || 0;
 75→  const [pointsValue, setPointsValue] = useState('');
 76→  const [reaisValue, setReaisValue] = useState('');
 77→  const [pointsError, setPointsError] = useState(false);
 78→  const [reaisError, setReaisError] = useState(false);
 79→  const convertionPrice = pointsQuantity * conversionFactor;
 80→  const convertionValue = new Intl.NumberFormat('pt-BR', {
 81→    style: 'currency',
 82→    currency: 'BRL',
 83→  }).format(convertionPrice);
 84→
 85→  const handleGoBack = () => {
 86→    navigation.goBack();
 87→  };
 88→
 89→  const handleContinue = () => {
 90→    eventSelectContent({
 91→      content_type: 'cta',
 92→      content_id: 'continuar',
 93→      location_1: 'monetizacao',
 94→      location_2: 'hub_recompensas_spmais',
 95→      location_3: 'desconto_fatura',
 96→    });
 97→
 98→    const reaisValue = conversionFactor * getParsePoints(pointsValue);
 99→
100→    navigation.navigate('InvoiceCashbackSummary', {
101→      pointsSelected: getParsePoints(pointsValue),
102→      reaisSelected: reaisValue,
103→      conversionFactor,
104→      productCode: route?.params?.productCode,
105→      campaingId: route?.params?.campaingId,
106→    });
107→  };
108→
109→  const invoiceList = (): CashbackInvoiceItem[] => {
110→    return [
111→      {
112→        type: 'default',
113→        icon: 'icon-switch-vertical',
114→        iconColor: 'BRAND_BASE_01',
115→        iconColorShape: 'INTENSE_COLOR_01',
116→        description: `Cada ${pointsQuantity.toLocaleString(
117→          'pt-br',
118→        )} pontos valem ${convertionValue} no cashback`,
119→      },
120→      {
121→        type: 'default',
122→        icon: 'icon-calendar',
123→        iconColor: 'BRAND_BASE_01',
124→        iconColorShape: 'INTENSE_COLOR_01',
125→        description:
126→          'Você define quanto cashback quer aplicar na sua fatura aberta',
127→      },
128→      {
129→        type: 'default',
130→        icon: 'icon-payment-invoice',
131→        iconColor: 'BRAND_BASE_01',
132→        iconColorShape: 'INTENSE_COLOR_01',
133→        description:
134→          'Se o valor for maior que o da fatura, a diferença será aplicada nas próximas',
135→      },
136→      {
137→        type: 'default',
138→        icon: 'icon-clock',
139→        iconColor: 'BRAND_BASE_01',
140→        iconColorShape: 'INTENSE_COLOR_01',
141→        description: 'O cashback acontece em até 72h',
142→      },
143→    ];
144→  };
145→  const rate = useMemo(() => {
146→    if (conversionFactor && conversionFactor > 0) {
147→      return conversionFactor;
148→    }
149→    return 0;
150→  }, [conversionFactor]);
151→
152→  const items: CashbackInvoiceItem[] = invoiceList();
153→
154→  const handleChangePoints = (text: string) => {
155→    const val = getParsePoints(text);
156→    const formatted = val ? getFormattedPoints(val) : '';
157→    setPointsValue(formatted);
158→
159→    if (rate > 0) {
160→      setReaisValue(val > 0 ? formatCurrencyBR(val * rate) : '');
161→    }
162→    if (val > (Math.trunc(Number(points)) || 0)) {
163→      setPointsError(true);
164→    } else {
165→      setPointsError(false);
166→    }
167→  };
168→
169→  const handleChangeReais = (text: string) => {
170→    const val = getParsedCurrency(text);
171→    const formatted = val > 0 ? formatCurrencyBR(val) : '';
172→    setReaisValue(formatted);
173→
174→    if (rate > 0) {
175→      const ptsFromReais = Math.round(val / rate);
176→      setPointsValue(ptsFromReais > 0 ? getFormattedPoints(ptsFromReais) : '');
177→    }
178→    if (val > finalPrice) {
179→      setReaisError(true);
180→    } else {
181→      setReaisError(false);
182→    }
183→  };
184→
185→  const handleUseAll = () => {
186→    setPointsValue(getFormattedPoints(points || 0));
187→    setReaisValue(formatCurrencyBR(finalPrice));
188→    setPointsError(false);
189→    setReaisError(false);
190→  };
191→
192→  useFocusEffect(
193→    React.useCallback(() => {
194→      setPointsValue('');
195→      setReaisValue('');
196→      setPointsError(false);
197→      setReaisError(false);
198→      return () => {
199→        setPointsValue('');
200→        setReaisValue('');
201→        setPointsError(false);
202→        setReaisError(false);
203→      };
204→    }, [
205→      setPointsValue,
206→      setReaisValue,
207→    ]),
208→  );
209→
210→  const modalizeRef1 = useRef<PropsModalizeRef>(
211→    null as unknown as PropsModalizeRef,
212→  );
213→
214→  const onOpenDefault = () => {
215→    eventSelectContent({
216→      content_type: 'cta',
217→      content_id: 'informacoes',
218→      location_1: 'monetizacao',
219→      location_2: 'hub_recompensas_spmais',
220→      location_3: 'desconto_fatura',
221→    });
222→
223→    modalizeRef1.current?.open?.();
224→
225→    eventModalView({
226→      content_id: 'info_desconto_fatura',
227→      location_1: 'monetizacao',
228→      location_2: 'hub_recompensas_spmais',
229→      location_3: 'desconto_fatura',
230→    });
231→  };
232→
233→  const handleModalizeContinue = () => {
234→    eventSelectContent({
235→      content_type: 'cta',
236→      content_id: 'entendi',
237→      location_1: 'monetizacao',
238→      location_2: 'hub_recompensas_spmais',
239→      location_3: 'info_desconto_fatura',
240→    });
241→
242→    modalizeRef1.current?.close?.();
243→  };
244→
245→  const handleSelectEvent = (contentId: string) => {
246→    eventSelectContent({
247→      content_type: 'form',
248→      content_id: contentId,
249→      location_1: 'monetizacao',
250→      location_2: 'hub_recompensas_spmais',
251→      location_3: 'desconto_fatura',
252→    });
253→  };
254→
255→  return (
256→    <InvoiceCashbackPointsView
257→      handleGoBack={handleGoBack}
258→      points={Math.trunc(Number(points)) || 0}
259→      handleContinue={handleContinue}
260→      price={pointsPrice}
261→      conversionFactor={conversionFactor}
262→      formattedPrice={formatCurrencyBR(finalPrice)}
263→      handleChangeReais={handleChangeReais}
264→      pointsValue={pointsValue}
265→      reaisValue={reaisValue}
266→      convertionValue={convertionValue}
267→      pointsQuantity={pointsQuantity}
268→      pointsError={pointsError}
269→      reaisError={reaisError}
270→      handleChangePoints={handleChangePoints}
271→      handleUseAll={handleUseAll}
272→      items={items}
273→      handleModalizeContinue={handleModalizeContinue}
274→      onOpenDefault={onOpenDefault}
275→      modalizeRef1={modalizeRef1}
276→      handleSelectEvent={handleSelectEvent}
277→      height={height}
278→      width={width}
279→      isLoadingParameterization={isLoadingParameterization}
280→    />
281→  );
282→};
283→
284→export default InvoiceCashbackPoints;
