 5→} from '@semparar/design-system-app';
 6→import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
 7→import { TextIconType } from '@semparar/design-system-app/src/atomic/molecules/TextIcon/Models';
 8→import React from 'react';
 9→import { PropsFintechCardRoutes } from '../../../routes/Models';
10→
11→export interface InvoiceCashbackViewProps {
12→  handleGoBack: () => void;
13→  handleContinue: () => void;
14→  cashbackInvoiceList?: CashbackInvoiceItem[];
15→  points: number;
16→  price?: number;
