17→interface ParsedData {
18→  categories: CategoryItem[];
19→}
20→
21→export function mapParameterPointsProgramResponse(
22→  response: ParameterPointsProgramResponse[],
23→): ParameterPointsProgramResponse[] {
24→  try {
25→    const find = response.find(
26→      item => item.category.toLowerCase() === 'saiba mais',
27→    );
28→
29→    if (!find || typeof find.value !== 'string') {
30→      return [];
31→    }
32→
33→    const data = JSON.parse(find.value) as ParsedData;
34→
35→    if (!data?.categories || !Array.isArray(data.categories)) {
36→      return [];
37→    }
38→
39→    return data.categories.map((
40→      item,
41→      index,
42→    ): ParameterPointsProgramResponse => {
43→      const value: ParameterPointsProgramValue = {
44→        questions: item.questions ?? [],
45→        order: item.order ?? index,
46→        icon: (item.icon as PropsIconsNameCore) ?? 'icon-help',
47→      };
48→
49→      return {
50→        category: item.category,
51→        value,
52→        dateCreated: find.dateCreated,
53→        status: find.status,
54→        PK: find.PK,
55→        dateUpdated: find.dateUpdated,
56→      };
57→    });
58→  } catch {
59→    return [];
60→  }
61→}
