 1→import { useRootStore } from '~/store';
 2→import { getParameterPointsProgramApi } from '../api';
 3→import { ParameterPointsProgramStatus } from '../models';
 4→import { mapParameterPointsProgramResponse } from '../repository';
 5→
 6→export async function getParameterPointsProgram(): Promise<void> {
 7→  const { parameterPointsProgramActions, parameterPointsProgram } =
 8→    useRootStore.getState();
 9→
10→  if (
11→    parameterPointsProgram.status === ParameterPointsProgramStatus.LOADING ||
12→    parameterPointsProgram.status === ParameterPointsProgramStatus.SUCCESS
13→  ) {
14→    return;
15→  }
16→
17→  try {
18→    parameterPointsProgramActions.setStatus(
19→      ParameterPointsProgramStatus.LOADING,
20→    );
21→
22→    const response = await getParameterPointsProgramApi();
23→
24→    if (response.status === 200 && response?.data?.length > 0) {
25→      const data = mapParameterPointsProgramResponse(response.data);
26→      parameterPointsProgramActions.setData(data);
27→      return;
28→    }
29→
30→    parameterPointsProgramActions.setStatus(ParameterPointsProgramStatus.ERROR);
31→  } catch {
32→    parameterPointsProgramActions.setStatus(ParameterPointsProgramStatus.ERROR);
33→  }
34→}
