 3→export function mapPointsProductsResponse(
 4→  response: PointsProductsApiResponse,
 5→): PointsProduct[] {
 6→  const products = response?.data?.products;
 7→  if (!products || !Array.isArray(products)) {
 8→    return [];
 9→  }
10→  return products;
11→}
12→
13→export function extractConversionFactor(products: PointsProduct[]): number {
14→  for (let i = 0; i < products.length; i++) {
15→    const product = products[i];
16→    if (product.convertionFactor && product.convertionFactor > 0) {
17→      return product.convertionFactor;
18→    }
19→  }
20→  return 0;
21→}
