 58→          });
 59→        }
 60→      };
 61→    },
 62→    [onPressKeyName],
 63→  );
 64→
 65→  const buildPointsCardItems = useCallback(
 66→    (pointsOptions: PointsProduct[] | undefined): PointsCardItem[] => {
 67→      const rawProducts = extractRawProducts(pointsOptions);
 68→      const builder = PointsCardItemBuilder.getInstance();
 69→
 70→      return rawProducts.filter(isValidProduct).map((product, index) => {
 71→        const normalizedName = normalizeName(product.name);
 72→        const icon = NAME_TO_ICON[normalizedName] || 'icon-default';
 73→
 74→        const isCashbackInInvoice =
 75→          normalizedName === normalizeName(KEY_NAME_TO_ICON.RESCUE_IN_INVOICE);
 76→        const onPress = isCashbackInInvoice
 77→          ? async () => {
 78→              eventSelectContent({
 79→                content_type: 'cta',
